import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { 
  FaMicrophone, 
  FaMicrophoneSlash, 
  FaVideo, 
  FaVideoSlash, 
  FaPhoneSlash, 
  FaVolumeUp, 
  FaVolumeMute, 
  FaCog, 
  FaExpand, 
  FaCompress,
  FaUserMd,
  FaComment,
  FaShareSquare
} from 'react-icons/fa';
import './VideoCallPage.css';

const VideoCallPage = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();
  const doctor = location.state?.doctor;

  // Call states
  const [callDuration, setCallDuration] = useState(0);
  const [isMuted, setIsMuted] = useState(false);
  const [isCameraOn, setIsCameraOn] = useState(true);
  const [isSpeakerOn, setIsSpeakerOn] = useState(true);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showControls, setShowControls] = useState(true);
  const [showChat, setShowChat] = useState(false);

  useEffect(() => {
    // Redirect if no doctor data
    if (!doctor) {
      navigate('/');
      return;
    }

    // Start call timer
    const timer = setInterval(() => {
      setCallDuration(prev => prev + 1);
    }, 1000);

    // Auto-hide controls after 3 seconds
    const controlsTimer = setTimeout(() => {
      setShowControls(false);
    }, 3000);

    return () => {
      clearInterval(timer);
      clearTimeout(controlsTimer);
    };
  }, [doctor, navigate]);

  // Show controls on mouse move
  useEffect(() => {
    const handleMouseMove = () => {
      setShowControls(true);
      const timer = setTimeout(() => {
        setShowControls(false);
      }, 3000);
      return () => clearTimeout(timer);
    };

    document.addEventListener('mousemove', handleMouseMove);
    return () => document.removeEventListener('mousemove', handleMouseMove);
  }, []);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleEndCall = () => {
    navigate('/');
  };

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  if (!doctor) {
    return null;
  }

  return (
    <div className="vc-page">
      <div className="vc-container">
        <aside className="vc-sidebar">
          <div className="vc-person vc-doctor">
            <div className="vc-avatar vc-avatar-doctor">{doctor.name?.charAt(0)}</div>
            <div className="vc-person-info">
              <div className="vc-name">{doctor.name}</div>
              <div className="vc-meta">{doctor.specialty}</div>
              <div className="vc-small">{doctor.qualifications}</div>
            </div>
          </div>

          <div className="vc-divider" />

          <div className="vc-person vc-patient">
            <div className="vc-avatar vc-avatar-patient">You</div>
            <div className="vc-person-info">
              <div className="vc-name">Patient</div>
              <div className="vc-meta">Camera: {isCameraOn ? 'On' : 'Off'}</div>
            </div>
          </div>

          <div className="vc-divider" />

          <div className="vc-stats">
            <div className="vc-timer">{formatTime(callDuration)}</div>
            <div className="vc-status">Available • {doctor.experience || 0} yrs</div>
            <div className="vc-langs">Languages: {doctor.languages || 'English'}</div>
          </div>
        </aside>

        <main className="vc-main">
          <header className="vc-main-header">
            <h1>Video Call</h1>
            <div className="vc-actions">
              <button onClick={toggleFullscreen} className="icon-btn" title={isFullscreen ? 'Exit Fullscreen' : 'Fullscreen'}>
                {isFullscreen ? <FaCompress /> : <FaExpand />}
              </button>
              <button onClick={() => setShowChat(!showChat)} className="icon-btn" title="Toggle Chat"><FaComment /></button>
            </div>
          </header>

          <div className={`vc-video-stage ${showControls ? 'show-controls' : ''}`} onMouseMove={() => setShowControls(true)}>
            <div className="vc-video-dummy">
              <div className="vc-dummy-overlay">
                <div className="vc-dummy-avatar">{doctor.name?.charAt(0)}</div>
                <div className="vc-dummy-info">
                  <div className="vc-dummy-name">{doctor.name}</div>
                  <div className="vc-dummy-specialty">{doctor.specialty}</div>
                  <div className="vc-dummy-status">Video Call Active</div>
                </div>
              </div>
            </div>

            <div className="vc-mini-video">
              {isCameraOn ? (
                <div className="mini-on">
                  <div className="mini-avatar">You</div>
                  <div className="mini-txt">Camera On</div>
                </div>
              ) : (
                <div className="mini-off"><FaVideoSlash /> Camera Off</div>
              )}
            </div>

            <div className={`vc-controls ${showControls ? 'visible' : ''}`}>
              <button className={`control-btn ${isMuted ? 'active muted' : ''}`} onClick={() => setIsMuted(!isMuted)} title={isMuted ? 'Unmute' : 'Mute'}>
                {isMuted ? <FaMicrophoneSlash /> : <FaMicrophone />}
              </button>

              <button className={`control-btn ${!isCameraOn ? 'active muted' : ''}`} onClick={() => setIsCameraOn(!isCameraOn)} title={isCameraOn ? 'Turn camera off' : 'Turn camera on'}>
                {isCameraOn ? <FaVideo /> : <FaVideoSlash />}
              </button>

              <button className="control-btn end" onClick={handleEndCall} title="End Call"><FaPhoneSlash /></button>

              <button className={`control-btn ${!isSpeakerOn ? 'active muted' : ''}`} onClick={() => setIsSpeakerOn(!isSpeakerOn)} title={isSpeakerOn ? 'Mute speaker' : 'Unmute speaker'}>
                {isSpeakerOn ? <FaVolumeUp /> : <FaVolumeMute />}
              </button>

              <button className="control-btn" title="Share screen"><FaShareSquare /></button>
            </div>
          </div>
        </main>

        {showChat && (
          <aside className="vc-chat">
            <div className="chat-header">
              <h3>Chat</h3>
              <button className="icon-btn" onClick={() => setShowChat(false)}><FaCompress /></button>
            </div>
            <div className="chat-body">Chat feature coming soon...</div>
          </aside>
        )}
      </div>
    </div>
  );
};

export default VideoCallPage;
